const raw = $input.first().json.text;

// Extract all "key":"value" pairs safely
const regex = /"([^"]+)"\s*:\s*"([\s\S]*?)"(,|$)/g;

let match;
const obj = {};

while ((match = regex.exec(raw)) !== null) {
  const key = match[1];
  let value = match[2];

  // Clean value
  value = value
    .replace(/\\n/g, "\n")   // convert escaped newlines
    .replace(/\n/g, " ")     // remove real line breaks
    .replace(/\\"/g, '"')   // fix escaped quotes
    .trim();

  obj[key] = value;
}

return obj;

